patch:
--- a/decoder.sv
+++ b/decoder.sv
@@ -1,13 +1,13 @@
 module decoder_3to8 (
   input [2:0] addr,
   input enable,
   output [7:0] out
 );
   assign out = enable ? (8'b1 << addr) : 8'b0;
 endmodule

 module processor;
   wire [2:0] address;
   wire en_signal;
-  decoder_3to8 inst (.addr(address), .out(decoded));
+  decoder_3to8 inst (.addr(address), .enable(en_signal), .out(decoded));
   wire [7:0] decoded;
 endmodule

before_code:
module decoder_3to8 (
  input [2:0] addr,
  input enable,
  output [7:0] out
);
  assign out = enable ? (8'b1 << addr) : 8'b0;
endmodule

module processor;
  wire [2:0] address;
  wire en_signal;
  decoder_3to8 inst (.addr(address), .out(decoded));
  wire [7:0] decoded;
endmodule

after_code:
module decoder_3to8 (
  input [2:0] addr,
  input enable,
  output [7:0] out
);
  assign out = enable ? (8'b1 << addr) : 8'b0;
endmodule

module processor;
  wire [2:0] address;
  wire en_signal;
  decoder_3to8 inst (.addr(address), .enable(en_signal), .out(decoded));
  wire [7:0] decoded;
endmodule
